import app from 'flarum/admin/app';
import AdminPage from 'flarum/admin/components/AdminPage';
import TeamsTab from './TeamsTab';
export default class PicksPage extends AdminPage {
  activeTab = 'teams';
  oninit(vnode) {
    super.oninit(vnode);

    // Restore tab from URL query param if present.
    const param = m.route.param('tab');
    const validTabs = ['dashboard', 'sync', 'seasons', 'teams', 'games', 'scores', 'settings'];
    if (param && validTabs.includes(param)) {
      this.activeTab = param;
    }
  }
  headerInfo() {
    return {
      className: 'PicksAdminPage',
      icon: 'fas fa-football',
      title: app.translator.trans('resofire-picks.admin.nav.picks'),
      description: app.translator.trans('resofire-picks.admin.page.description')
    };
  }
  content() {
    return m("div", {
      className: "PicksAdminPage-body"
    }, m("div", {
      className: "PicksAdminPage-tabs"
    }, this.renderTab('teams', 'fas fa-users', 'resofire-picks.admin.nav.teams'), this.renderTab('sync', 'fas fa-sync', 'resofire-picks.admin.nav.sync'), this.renderTab('seasons', 'fas fa-calendar-alt', 'resofire-picks.admin.nav.seasons'), this.renderTab('games', 'fas fa-football', 'resofire-picks.admin.nav.games'), this.renderTab('scores', 'fas fa-trophy', 'resofire-picks.admin.nav.scores'), this.renderTab('settings', 'fas fa-cog', 'resofire-picks.admin.nav.settings')), m("div", {
      className: "PicksAdminPage-content"
    }, this.renderActiveTab()));
  }
  renderTab(key, icon, translationKey) {
    const isActive = this.activeTab === key;
    return m("button", {
      className: `Button PicksAdminPage-tab ${isActive ? 'Button--primary' : ''}`,
      onclick: () => {
        this.activeTab = key;
        const base = m.route.get().split('?')[0];
        m.route.set(base, {
          tab: key
        }, {
          replace: true
        });
      }
    }, m("i", {
      className: icon
    }), ' ', app.translator.trans(translationKey));
  }
  renderActiveTab() {
    switch (this.activeTab) {
      case 'teams':
        return m(TeamsTab, null);
      case 'sync':
        // Built in Slice 3 (schedule sync) and Slice 8 (score sync).
        return m("div", {
          className: "PicksPlaceholder"
        }, app.translator.trans('resofire-picks.admin.placeholder.coming_soon'));
      case 'seasons':
        // Built in Slice 3.
        return m("div", {
          className: "PicksPlaceholder"
        }, app.translator.trans('resofire-picks.admin.placeholder.coming_soon'));
      case 'games':
        // Built in Slice 4.
        return m("div", {
          className: "PicksPlaceholder"
        }, app.translator.trans('resofire-picks.admin.placeholder.coming_soon'));
      case 'scores':
        // Built in Slice 7.
        return m("div", {
          className: "PicksPlaceholder"
        }, app.translator.trans('resofire-picks.admin.placeholder.coming_soon'));
      case 'settings':
        // Built in Slice 9.
        return m("div", {
          className: "PicksPlaceholder"
        }, app.translator.trans('resofire-picks.admin.placeholder.coming_soon'));
      default:
        return m(TeamsTab, null);
    }
  }
}
flarum.reg.add('resofire-picks', 'admin/components/PicksPage', PicksPage);